        "front": "Apakah yang dimaksudkan dengan bahan pembinaan?",
        "back": "Bahan pembinaan adalah elemen asas dalam setiap projek pembinaan, termasuk kayu, batu, konkrit, dan logam."
      },
      {
        "front": "Sebutkan satu kelebihan kayu sebagai bahan pembinaan.",
        "back": "Kelebihan kayu adalah ia ringan, mudah diproses, dan mempunyai sifat penebat yang baik."
      },
      {
        "front": "Senaraikan dua jenis bahan pembinaan yang biasa digunakan.",
        "back": "Dua jenis bahan pembinaan yang biasa digunakan adalah konkrit dan logam."
      },
      {
        "front": "Apa yang perlu dipertimbangkan ketika memilih bahan pembinaan?",
        "back": "Kelebihan, kekurangan, kos, dan kesesuaian untuk projek tertentu."
      }
    ]
  }
